import{_ as i,c as t,o as l,a1 as s}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Быстрый старт: Установка, настройка, запуск Gateway и первая пара сообщений с DM Pairing Protection | Clawdbot","description":"В этом разделе вы узнаете, как начать работу с Clawdbot: установка, настройка, запуск Gateway, отправка первого сообщения и знакомство с механизмом DM Pairing Protection.","frontmatter":{"title":"Быстрый старт: Установка, настройка, запуск Gateway и первая пара сообщений с DM Pairing Protection | Clawdbot","sidebarTitle":"Начало работы с нуля","subtitle":"Быстрый старт: от установки до первого сообщения","description":"В этом разделе вы узнаете, как начать работу с Clawdbot: установка, настройка, запуск Gateway, отправка первого сообщения и знакомство с механизмом DM Pairing Protection.","tags":["Начало работы","Быстрый старт"],"prerequisite":[],"order":10},"headers":[],"relativePath":"ru/moltbot/moltbot/start/index.md","filePath":"ru/moltbot/moltbot/start/index.md"}'),r={name:"ru/moltbot/moltbot/start/index.md"};function e(n,a,o,p,g,h){return l(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="быстрыи-старт-от-установки-до-первого-сообщения" tabindex="-1">Быстрый старт: от установки до первого сообщения <a class="header-anchor" href="#быстрыи-старт-от-установки-до-первого-сообщения" aria-label="Permalink to &quot;Быстрый старт: от установки до первого сообщения&quot;">​</a></h1><p>Добро пожаловать в Clawdbot! В этом разделе вы пройдёте полный путь от нуля до работающего AI-ассистента. Быстрый обзор возможностей или детальное изучение параметров — здесь найдётся всё необходимое.</p><hr><h2 id="обзор-раздела" tabindex="-1">Обзор раздела <a class="header-anchor" href="#обзор-раздела" aria-label="Permalink to &quot;Обзор раздела&quot;">​</a></h2><p>Этот раздел содержит 5 руководств, охватывающих весь процесс начала работы: от установки программного обеспечения и настройки AI-моделей и каналов связи до запуска демона Gateway, отправки первого сообщения и изучения встроенных механизмов безопасности. По завершении этого раздела у вас будет полноценный персональный AI-ассистент.</p><hr><h2 id="рекомендуемыи-порядок-изучения" tabindex="-1">Рекомендуемый порядок изучения <a class="header-anchor" href="#рекомендуемыи-порядок-изучения" aria-label="Permalink to &quot;Рекомендуемый порядок изучения&quot;">​</a></h2><p>Мы рекомендуем изучать эти руководства в следующем порядке:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[getting-started&lt;br&gt;Быстрый старт] --&gt; B[onboarding-wizard&lt;br&gt;Мастер настройки]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[gateway-startup&lt;br&gt;Запуск Gateway]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[first-message&lt;br&gt;Первое сообщение]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[pairing-approval&lt;br&gt;DM Pairing и контроль доступа]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#3b82f6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#10b981,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#f59e0b,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#8b5cf6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#ef4444,color:#fff</span></span></code></pre></div><p><strong>Пояснения к порядку обучения</strong>:</p><ol><li><strong>Быстрый старт</strong> (обязательно): базовая установка и настройка — основа для всего последующего обучения</li><li><strong>Мастер настройки</strong> (рекомендуется): детальное изучение опций мастера для пользователей, желающих тонко настроить систему</li><li><strong>Запуск Gateway</strong> (обязательно): запуск и управление демоном Gateway</li><li><strong>Первое сообщение</strong> (обязательно): проверка правильности настройки и начало работы с AI-ассистентом</li><li><strong>DM Pairing и контроль доступа</strong> (рекомендуется): изучение встроенных механизмов безопасности для защиты вашего AI-ассистента</li></ol><div class="tip custom-block"><p class="custom-block-title">Быстрый путь</p><p>Если вам нужно быстро попробовать Clawdbot, изучите только «Быстрый старт» и «Запуск Gateway», после чего сразу отправьте сообщение. Остальные руководства можно изучить позже по мере необходимости.</p></div><hr><h2 id="требования" tabindex="-1">Требования <a class="header-anchor" href="#требования" aria-label="Permalink to &quot;Требования&quot;">​</a></h2><p>Перед началом изучения этого раздела убедитесь, что у вас есть:</p><ul><li><strong>Node.js</strong>: ≥ 22.12.0 (проверьте командой <code>node -v</code>)</li><li><strong>Операционная система</strong>: macOS / Linux / Windows (WSL2)</li><li><strong>Менеджер пакетов</strong>: npm / pnpm / bun</li><li><strong>Аккаунт AI-модели</strong> (рекомендуется): <ul><li>Аккаунт Anthropic Claude (подписка Pro/Max) с поддержкой OAuth-авторизации</li><li>Или API Key от провайдеров OpenAI / DeepSeek / OpenRouter</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Внимание пользователям Windows</p><p>На <strong>Windows настоятельно рекомендуется использовать WSL2</strong>, так как:</p><ul><li>Многие каналы зависят от локальных бинарных файлов</li><li>Демоны (launchd/systemd) недоступны в Windows</li></ul></div><hr><h2 id="навигация-по-подразделам" tabindex="-1">Навигация по подразделам <a class="header-anchor" href="#навигация-по-подразделам" aria-label="Permalink to &quot;Навигация по подразделам&quot;">​</a></h2><h3 id="_1-быстрыи-старт-⭐-основное-руководство" tabindex="-1"><a href="./getting-started/">1. Быстрый старт</a> ⭐ Основное руководство <a class="header-anchor" href="#_1-быстрыи-старт-⭐-основное-руководство" aria-label="Permalink to &quot;[1. Быстрый старт](./getting-started/) ⭐ Основное руководство&quot;">​</a></h3><p><strong>Что вы сможете делать после изучения</strong>:</p><ul><li>✅ Установить Clawdbot на ваше устройство</li><li>✅ Настроить аутентификацию AI-модели (Anthropic / OpenAI / другие провайдеры)</li><li>✅ Запустить демон Gateway</li><li>✅ Отправить первое сообщение через WebChat или настроенный канал</li></ul><p><strong>Для кого</strong>: все пользователи, обязательное к изучению</p><p><strong>Примерное время</strong>: 15-20 минут</p><p><strong>Основное содержание</strong>:</p><ul><li>Установка Clawdbot через npm/pnpm/bun</li><li>Запуск мастера начальной настройки (onboarding)</li><li>Запуск Gateway и проверка статуса</li><li>Отправка тестового сообщения через CLI или канал</li></ul><p><strong>Требования</strong>: отсутствуют</p><hr><h3 id="_2-мастер-настроики" tabindex="-1"><a href="./onboarding-wizard/">2. Мастер настройки</a> <a class="header-anchor" href="#_2-мастер-настроики" aria-label="Permalink to &quot;[2. Мастер настройки](./onboarding-wizard/)&quot;">​</a></h3><p><strong>Что вы сможете делать после изучения</strong>:</p><ul><li>✅ Использовать интерактивный мастер для полной настройки</li><li>✅ Понимать разницу между режимами QuickStart и Manual</li><li>✅ Настраивать сеть Gateway, аутентификацию и Tailscale</li><li>✅ Настраивать провайдеров AI-моделей (setup-token и API Key)</li><li>✅ Включать каналы связи (WhatsApp, Telegram и др.)</li><li>✅ Устанавливать и управлять пакетами навыков</li></ul><p><strong>Для кого</strong>: пользователи, желающие тонко настроить систему и изучить расширенные опции</p><p><strong>Примерное время</strong>: 20-30 минут</p><p><strong>Основное содержание</strong>:</p><ul><li>Выбор между режимами QuickStart и Manual</li><li>Настройка сети Gateway (порты, привязка, аутентификация)</li><li>Способы аутентификации AI-модели (рекомендуется setup-token)</li><li>Процесс настройки каналов связи</li><li>Введение в систему навыков</li></ul><p><strong>Требования</strong>: <a href="./getting-started/">Быстрый старт</a></p><hr><h3 id="_3-запуск-gateway-⭐-основное-руководство" tabindex="-1"><a href="./gateway-startup/">3. Запуск Gateway</a> ⭐ Основное руководство <a class="header-anchor" href="#_3-запуск-gateway-⭐-основное-руководство" aria-label="Permalink to &quot;[3. Запуск Gateway](./gateway-startup/) ⭐ Основное руководство&quot;">​</a></h3><p><strong>Что вы сможете делать после изучения</strong>:</p><ul><li>✅ Запускать Gateway в foreground-режиме через командную строку</li><li>✅ Настраивать Gateway как фоновый демон (macOS LaunchAgent / Linux systemd / Windows Scheduled Task)</li><li>✅ Понимать различия между режимами привязки (loopback / LAN / Tailnet) и способами аутентификации</li><li>✅ Переключаться между режимами разработки и продакшена</li><li>✅ Использовать <code>--force</code> для принудительного освобождения занятого порта</li></ul><p><strong>Для кого</strong>: все пользователи, обязательное к изучению</p><p><strong>Примерное время</strong>: 15-20 минут</p><p><strong>Основное содержание</strong>:</p><ul><li>Режим foreground vs демон</li><li>Выбор режима привязки (loopback / LAN / Tailnet / Auto)</li><li>Настройка аутентификации (Token / Password / Tailscale Identity)</li><li>Режим разработки (<code>--dev</code>) и продакшен</li><li>Команды управления сервисом (install / start / stop / restart)</li><li>Разрешение конфликтов портов (<code>--force</code>)</li></ul><p><strong>Требования</strong>: <a href="./onboarding-wizard/">Мастер настройки</a></p><hr><h3 id="_4-отправка-первого-сообщения-⭐-основное-руководство" tabindex="-1"><a href="./first-message/">4. Отправка первого сообщения</a> ⭐ Основное руководство <a class="header-anchor" href="#_4-отправка-первого-сообщения-⭐-основное-руководство" aria-label="Permalink to &quot;[4. Отправка первого сообщения](./first-message/) ⭐ Основное руководство&quot;">​</a></h3><p><strong>Что вы сможете делать после изучения</strong>:</p><ul><li>✅ Отправлять сообщения через интерфейс WebChat</li><li>✅ Общаться с AI-ассистентом через настроенные каналы (WhatsApp / Telegram / Slack и др.)</li><li>✅ Понимать маршрутизацию сообщений и процесс ответов</li><li>✅ Использовать AI-ассистента для базовых задач (поиск информации, генерация кода, суммирование и т.д.)</li></ul><p><strong>Для кого</strong>: все пользователи, обязательное к изучению</p><p><strong>Примерное время</strong>: 10-15 минут</p><p><strong>Основное содержание</strong>:</p><ul><li>Использование интерфейса WebChat</li><li>Способы отправки сообщений в различных каналах</li><li>Формат сообщений и механизм ответов</li><li>Примеры типовых задач (поиск информации, генерация кода, суммирование текста)</li><li>Отладка и устранение неполадок</li></ul><p><strong>Требования</strong>: <a href="./gateway-startup/">Запуск Gateway</a></p><hr><h3 id="_5-dm-pairing-и-контроль-доступа" tabindex="-1"><a href="./pairing-approval/">5. DM Pairing и контроль доступа</a> <a class="header-anchor" href="#_5-dm-pairing-и-контроль-доступа" aria-label="Permalink to &quot;[5. DM Pairing и контроль доступа](./pairing-approval/)&quot;">​</a></h3><p><strong>Что вы сможете делать после изучения</strong>:</p><ul><li>✅ Понимать механизм защиты DM Pairing по умолчанию</li><li>✅ Одобрять или отклонять запросы на pairing от незнакомых отправителей</li><li>✅ Настраивать белые и чёрные списки</li><li>✅ Настраивать политики контроля доступа</li><li>✅ Понимать режимы pairing и лучшие практики безопасности</li></ul><p><strong>Для кого</strong>: пользователи, озабоченные безопасностью, рекомендуется к изучению</p><p><strong>Примерное время</strong>: 10-15 минут</p><p><strong>Основное содержание</strong>:</p><ul><li>Принцип работы механизма DM Pairing</li><li>Процесс pairing и пользовательский опыт</li><li>Настройка белых и чёрных списков</li><li>Настройка политик контроля доступа</li><li>Лучшие практики безопасности</li></ul><p><strong>Требования</strong>: <a href="./first-message/">Отправка первого сообщения</a></p><hr><h2 id="часто-задаваемые-вопросы" tabindex="-1">Часто задаваемые вопросы <a class="header-anchor" href="#часто-задаваемые-вопросы" aria-label="Permalink to &quot;Часто задаваемые вопросы&quot;">​</a></h2><h3 id="в-нужно-ли-изучать-все-руководства" tabindex="-1">В: Нужно ли изучать все руководства? <a class="header-anchor" href="#в-нужно-ли-изучать-все-руководства" aria-label="Permalink to &quot;В: Нужно ли изучать все руководства?&quot;">​</a></h3><p><strong>О</strong>: Не обязательно. Если вам нужно быстро начать работу, достаточно изучить два основных руководства — «Быстрый старт» и «Запуск Gateway», после чего можно сразу использовать Clawdbot. Остальные руководства можно изучать по мере необходимости.</p><h3 id="в-будет-ли-проблемои-если-я-пропущу-некоторые-руководства" tabindex="-1">В: Будет ли проблемой, если я пропущу некоторые руководства? <a class="header-anchor" href="#в-будет-ли-проблемои-если-я-пропущу-некоторые-руководства" aria-label="Permalink to &quot;В: Будет ли проблемой, если я пропущу некоторые руководства?&quot;">​</a></h3><p><strong>О</strong>: Нет. Каждое руководство самодостаточно, но «Быстрый старт» является основой, содержащей установку и базовую настройку, поэтому рекомендуется начать с него. Другие руководства можно изучать выборочно в зависимости от ваших потребностей.</p><h3 id="в-я-уже-знаком-с-ai-ассистентами-могу-ли-я-пропустить-базовые-руководства" tabindex="-1">В: Я уже знаком с AI-ассистентами, могу ли я пропустить базовые руководства? <a class="header-anchor" href="#в-я-уже-знаком-с-ai-ассистентами-могу-ли-я-пропустить-базовые-руководства" aria-label="Permalink to &quot;В: Я уже знаком с AI-ассистентами, могу ли я пропустить базовые руководства?&quot;">​</a></h3><p><strong>О</strong>: Да. Если вы уже знакомы с подобными инструментами AI-ассистентов, вы можете пропустить «Быстрый старт» и сразу перейти к «Мастеру настройки» и «Запуску Gateway», чтобы узнать о специфических параметрах и способах запуска Clawdbot.</p><h3 id="в-что-я-смогу-делать-после-изучения-этого-раздела" tabindex="-1">В: Что я смогу делать после изучения этого раздела? <a class="header-anchor" href="#в-что-я-смогу-делать-после-изучения-этого-раздела" aria-label="Permalink to &quot;В: Что я смогу делать после изучения этого раздела?&quot;">​</a></h3><p><strong>О</strong>: После завершения этого раздела у вас будет работающая система Clawdbot, позволяющая:</p><ul><li>Общаться с AI-ассистентом через WebChat или несколько каналов</li><li>Поручать AI выполнение базовых задач (поиск информации, генерация кода, суммирование текста и т.д.)</li><li>Использовать механизм DM Pairing для обеспечения безопасности</li><li>Продолжить изучение расширенных функций (многоканальная настройка, система инструментов, платформа навыков и т.д.)</li></ul><hr><h2 id="куда-двигаться-дальше" tabindex="-1">Куда двигаться дальше <a class="header-anchor" href="#куда-двигаться-дальше" aria-label="Permalink to &quot;Куда двигаться дальше&quot;">​</a></h2><p>После завершения этого раздела вы можете продолжить обучение:</p><ul><li><strong><a href="./../../platforms/channels-overview/">Обзор многоканальной системы</a></strong>: узнайте обо всех поддерживаемых каналах связи и их особенностях</li><li><strong><a href="./../../platforms/whatsapp/">Канал WhatsApp</a></strong>: углублённое изучение настройки и использования канала WhatsApp</li><li><strong><a href="./../../platforms/telegram/">Канал Telegram</a></strong>: углублённое изучение настройки и использования канала Telegram</li><li><strong><a href="./../../platforms/webchat/">Интерфейс WebChat</a></strong>: изучение возможностей встроенного интерфейса WebChat</li></ul><div class="tip custom-block"><p class="custom-block-title">Подсказка</p><p>В зависимости от ваших потребностей выбирайте соответствующий канал для углублённого изучения. Если вы в основном используете определённый канал (например, WhatsApp или Telegram), можете начать с соответствующего руководства.</p></div>`,79)])])}const u=i(r,[["render",e]]);export{c as __pageData,u as default};
